function tickWeather() {
    const cur = weatherAt(now()); if (!cur) return;
    const key = cur.cyc + '-' + cur.pi;
    if (key !== lastWKey) { lastWKey = key; renderWeather(); return; }
    const data = weatherRowsData();
    document.querySelectorAll('#rows .row').forEach((el, i) => {
        const b = el.querySelector('.next-badge'); if (b && data[i]) b.textContent = data[i].label;
    });
}
function tickCards() {
    if (TAB === 'weather') { tickWeather(); return; }
    const t = now();
    const w = Math.floor(t / PERIOD);
    if (w !== lastWindow) { lastWindow = w; render(); return; }
    document.querySelectorAll('#rows .row').forEach((el, i) => {
        const item = VIEW[i]; if (!item) return; const ev = evalItem(item);
        const cd = el.querySelector('.cd');
        if (cd && ev.nxt) cd.textContent = shortDur(ev.nxt.t - t);
    });
}
function setTab(tab) {
    TAB = tab;
    document.getElementById('tabSeeds').classList.toggle('active', tab === 'seeds');
    document.getElementById('tabGears').classList.toggle('active', tab === 'gears');
    document.getElementById('tabWeather').classList.toggle('active', tab === 'weather');
    lastWKey = ''; render(); tickGlobal();
}
document.getElementById('tabSeeds').onclick = () => setTab('seeds');
document.getElementById('tabGears').onclick = () => setTab('gears');
document.getElementById('tabWeather').onclick = () => setTab('weather');

if (DATA) {
    PERIOD = DATA.period || 300;
    lastWindow = Math.floor(now() / PERIOD);
    render(); tickGlobal();
    setInterval(() => { tickGlobal(); tickCards(); }, 1000);
} else {
    document.getElementById('empty').classList.remove('hidden');
}
